/**
 * MedX autofill forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Browser autofill detection and overrides.
 */
const AUTOFILL_TOKENS = Object.freeze({
  primary: { value: "forms-autofill-primary", scope: "forms" },
  secondary: { value: "forms-autofill-secondary", scope: "forms" },
  muted: { value: "forms-autofill-muted", scope: "forms" },
  accent: { value: "forms-autofill-accent", scope: "forms" },
  surface: { value: "forms-autofill-surface", scope: "forms" },
});

const AUTOFILL_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const AUTOFILL_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const autofillRegistry = new Map();
const AUTOFILL_listeners = new Set();
let AUTOFILL_seq = 0;

function createAutofillId(prefix = "medx-forms-autofill") {
  AUTOFILL_seq += 1;
  return `${prefix}-${AUTOFILL_seq}`;
}

function registerAutofill(config = {}) {
  const entryId = config.id ?? createAutofillId();
  const preset = AUTOFILL_PRESETS[config.preset ?? "default"] ?? AUTOFILL_PRESETS.default;
  const token = AUTOFILL_TOKENS[config.token ?? preset.token] ?? AUTOFILL_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: AUTOFILL_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  autofillRegistry.set(entryId, entry);
  notifyAutofillListeners("register", entry);
  return entry;
}

function updateAutofill(id, patch = {}) {
  const entry = autofillRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyAutofillListeners("update", entry);
  return entry;
}

function resolveAutofill(id) {
  const entry = autofillRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listAutofillEntries(filter = {}) {
  let items = Array.from(autofillRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onAutofillEvent(listener) {
  AUTOFILL_listeners.add(listener);
  return () => AUTOFILL_listeners.delete(listener);
}

function notifyAutofillListeners(type, entry) {
  for (const listener of AUTOFILL_listeners) {
    try {
      listener({ type, entry, registrySize: autofillRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:autofill] listener error", err.message);
    }
  }
}

function getAutofillMetrics() {
  const items = listAutofillEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(AUTOFILL_TOKENS).length,
    presets: Object.keys(AUTOFILL_PRESETS).length,
  };
}

async function runMedxAutofill() {
  console.log("[medx:ui:forms:autofill] runtime initialized");
  console.log(`[medx:ui:forms:autofill] tokens=${Object.keys(AUTOFILL_TOKENS).length} presets=${Object.keys(AUTOFILL_PRESETS).length}`);

  const events = [];
  onAutofillEvent((e) => events.push(e.type));

  const domains = Object.keys(AUTOFILL_SUPPLY_CHAIN);
  const presets = Object.keys(AUTOFILL_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerAutofill({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/autofill" },
    });
  }

  const first = listAutofillEntries()[0];
  if (first) updateAutofill(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getAutofillMetrics();
  const resolved = first ? resolveAutofill(first.id) : null;

  console.log(`[medx:ui:forms:autofill] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:autofill] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:autofill] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:autofill] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:autofill] bootstrap complete");
}

module.exports = runMedxAutofill;
